print(f"  اختبار متقدم — 30 سؤال شديد التعقيد — النموذج: {MODEL}")
print("=" * 70)

for i, q in enumerate(QUESTIONS):
    q_short = q[:50]
    try:
        d, elapsed = call_api(q)
        answer = d.get("answer", "")
        conf = d.get("confidence", 0) or 0
        known = d.get("from_known_answer", False)
        sources = d.get("sources", [])
        has_eng = bool(re.findall(r'[A-Za-z]{3,}(?:\s+[A-Za-z]{3,}){2,}', answer))
        has_answer = len(answer) > 50 and "خطأ تقني" not in answer

        total_conf += conf
        total_time += elapsed

        if has_answer and not has_eng:
            status = "OK"; ok += 1
        elif has_answer:
            status = "WARN"; warn += 1
        else:
            status = "ERR"; err += 1

        ans_preview = answer.replace("\n", " ")[:300]
        print(f"\n  #{i+1:2d} | {q_short}...")
        print(f"       الرد: {ans_preview[:250]}")
        print(f"       الثقة: {conf}% | RAG: {len(sources)} | وقت: {elapsed:.1f}s | [{status}]")
        results.append({"num": i+1, "q_short": q_short, "status": status, "conf": conf, "time": elapsed, "ans_len": len(answer), "sources": len(sources), "known": known, "answer_preview": ans_preview[:400]})
    except Exception as e:
        es = str(e)
        if "timed out" in es:
            timeout_c += 1; status = "TIMEOUT"
        else:
            err += 1; status = "ERR"
        print(f"\n  #{i+1:2d} | {q_short}...")
        print(f"       [{status}] {es[:80]}")
        results.append({"num": i+1, "q_short": q_short, "status": status, "error": es[:100]})
    time.sleep(3)

answered = ok + warn
total = len(QUESTIONS)

print(f"\n\n{'=' * 70}")
print("  النتائج الإجمالية")
print("=" * 70)
print(f"  نجاح:   {ok}/30 ({100*ok/30:.0f}%)")
print(f"  مقبول:  {warn}/30")
print(f"  فشل:    {err}/30")
print(f"  timeout: {timeout_c}/30")
if answered > 0:
    print(f"  متوسط الثقة: {total_conf/answered:.0f}%")
    print(f"  متوسط الوقت: {total_time/answered:.1f}s")

# Best 3
ok_results = [r for r in results if r["status"] == "OK"]
ok_results.sort(key=lambda x: x.get("conf", 0), reverse=True)
print(f"\n  أفضل 3 ردود (أعلى ثقة):")
for r in ok_results[:3]:
    print(f"    #{r['num']} conf={r['conf']}% | {r['q_short'][:40]}")

# Worst 3
ok_results.sort(key=lambda x: x.get("conf", 100))
print(f"\n  أقل 3 ردود ثقة:")
for r in ok_results[:3]:
    print(f"    #{r['num']} conf={r['conf']}% | {r['q_short'][:40]}")

with open("scripts/test_advanced_30_results.json", "w", encoding="utf-8") as f:
    json.dump({"ok": ok, "warn": warn, "err": err, "timeout": timeout_c,
               "avg_conf": round(total_conf/max(answered,1), 1),
               "avg_time": round(total_time/max(answered,1), 1),
               "results": results}, f, ensure_ascii=False, indent=2)
print(f"\n  محفوظة: scripts/test_advanced_30_results.json")
